#!/bin/bash
# Self-extracting installer for xploreum legal-bundle
# Run from the repo root: bash install-legal-bundle.sh
set -e

if [ ! -f "package.json" ]; then
  echo "ERROR: run this from the xploreum-landing repo root (where package.json lives)"
  exit 1
fi

echo "Decoding bundle..."
base64 -d > /tmp/legal-bundle.zip << 'B64_EOF'

B64_EOF

echo "Extracting..."
unzip -o /tmp/legal-bundle.zip -d .
rm /tmp/legal-bundle.zip

echo ""
echo "Done. Contents of legal-bundle/:"
ls legal-bundle/
echo ""
echo "Next: git add legal-bundle && git commit -m 'chore: add legal bundle' && git push"

